mapper.select:
SELECT tb_position_change.*, tb_user.employee_number, tb_user.nick_name, tb_department.dept_name FROM tb_position_change INNER JOIN tb_user ON tb_position_change.user_id = tb_user.id AND tb_user.is_deleted = 0 LEFT JOIN tb_department ON tb_user.department_id = tb_department.id AND tb_department.is_deleted = 0 WHERE tb_position_change.is_deleted = 0
AND tb_user.nick_name LIKE CONCAT('%', #{dto.nickName, jdbcType=VARCHAR}, '%')
AND tb_user.employee_number = #{dto.employeeNumber, jdbcType=VARCHAR}
AND ( tb_department.full_id LIKE CONCAT('%-', #{dto.departmentId}) OR tb_department.full_id LIKE CONCAT('%-', #{dto.departmentId}, '-%') )
AND tb_position_change.change_type = #{dto.changeType, jdbcType=TINYINT}
ORDER BY tb_position_change.id DESC
